import { Components } from "./@still/setup/components.js";
import { AppTemplate } from "./app-template.js";
import { HomeComponent } from "./app/home/HomeComponent.js";

export class StillAppSetup extends StillAppMixin(Components) {

    constructor() {
        super();
        //Defines the first component to load
        this.setHomeComponent(HomeComponent);
    }

    async init() {
        //Loads the app container and the initial component set at line 11
        return await AppTemplate.newApp();
    }

}
</code></pre> Routes will be added and manage automatically from here when creating the component using still-cli<pre><code>export const stillRoutesMap = {
    viewRoutes: {
        regular: {
            HomeComponent: { path: "app/home", url: "/HomeComponent" }
        },
        lazyInitial: {}
    }
}
</code></pre> HomeComponent.js<pre><code>import { ViewComponent } from "../../@still/component/super/ViewComponent.js";

export class HomeComponent extends ViewComponent {

    /** Need in any component as long as not dealing with parts 
     * only accessible in case of authenticated user
     * */
    isPublic = true;

    /**
     * constructor for still.js might be needed in very specific
     * situations (e.g. for using whenReady() Hook)
    */
    constructor() {
        super();
    }
}
</code></pre> <p>Conceptually, all components extends from ViewComponent, and, behide the, therefore, such extending component can serve as a whole page or a simple part of a specific page.</p> <p> </p>

