import { Components } from "./@still/setup/components.js";
import { AppTemplate } from "./app-template.js";
import { BiddingDisplay } from "./app/components/bidding/BiddingDisplay.js";

export class StillAppSetup extends StillAppMixin(Components) {

    constructor() {
        super();
        this.setHomeComponent(BiddingDisplay);
    }

    async init() {
        return await AppTemplate.newApp();
    }

}
</code></pre> <pre><code>export const stillRoutesMap = {
    viewRoutes: {
        regular: {
            BiddingDisplay: {
                path: "app/components/bidding",
                url: "/bid/display"
            },
            BidOffersComponent: {
                path: "app/components/bidding",
                url: "/bid/offer"
            },
        },
        lazyInitial: {}
    }
}
</code></pre> Parent Component<pre><code>import { ViewComponent } from "../../../@still/component/super/ViewComponent.js";

export class BiddingDisplay extends ViewComponent {

    isPublic = true;

    template = `
        &lt;st-element 
            component="BidOffersComponent"
            hieghestOffer="30"
            leadBidderName="Gregor"
        &gt;&lt;/st-element&gt;
    `;
}
</code></pre> Child Component called inside BiddingDisplay<pre><code>import { ViewComponent } from "../../../@still/component/super/ViewComponent.js";

export class BidOffersComponent extends ViewComponent {

    isPublic = true;

    hieghestOffer = 0;
    leadBidderName = null;

    template = `
        &lt;span&gt;Hier Offer&lt;/span&gt; @hieghestOffer
        &lt;span&gt;The leading Bidder is @leadBidderName&lt;/span&gt;
    `;

}
</code></pre> <p>Parent component is passing 2 (hieghestOffer, leadBidderName) properties  when referencing the child, those are states variables in the child whichwill be overriden.</p> <p>Just like it's possible to update child state by passing if as property in <code>&lt;st-element&gt;</code> tag, we can also pass method as follow:</p> BiddingDisplay.jsBidOffersComponent.js Parent Component<pre><code>import { ViewComponent } from "../../../@still/component/super/ViewComponent.js";

export class BiddingDisplay extends ViewComponent {

    isPublic = true;

    template = `
        &lt;st-element 
            component="BidOffersComponent"
            hieghestOffer="30"
            leadBidderName="Gregor"
            (myMethodSignature)="alertMyChild()"
        &gt;&lt;/st-element&gt;
    `;

    alertMyChild(){
        alert('Hello my child')
    }
}
</code></pre> Child Component<pre><code>import { ViewComponent } from "../../../@still/component/super/ViewComponent.js";

export class BidOffersComponent extends ViewComponent {

    isPublic = true;

    hieghestOffer = 0;
    leadBidderName = null;

    template = `
        &lt;span&gt;Hier Offer&lt;/span&gt; @hieghestOffer
        &lt;span&gt;The leading Bidder is @leadBidderName&lt;/span&gt;
        &lt;button (click)="myMethodSignature()"&gt;Call Parent Function&lt;/button&gt;
    `;


    myMethodSignature(){}

}
</code></pre> <p>Unlike state and property variables, method on the <code>&lt;st-element&gt;</code> component need to be references in paranthesis (), also, normally in the child we'll have the method signature, nevertheless we can also have it's own scope.</p> <p>It's also possible for the child to pass values to parent when executing method signature, follow the example:</p> BiddingDisplay.jsBidOffersComponent.js Parent Component<pre><code>import { ViewComponent } from "../../../@still/component/super/ViewComponent.js";

export class BiddingDisplay extends ViewComponent {

    isPublic = true;

    template = `
        &lt;st-element 
            (processMyData)="alertMyChild()"
        &gt;&lt;/st-element&gt;
    `;

    printChildDetailes(age, name){
        console.log(`Hello ${name} you're ${age} years old!`)
    }
}
</code></pre> <p>```js title="Child Component" hl_lines="8 13" linenums="1" import { ViewComponent } from "../../../@still/component/super/ViewComponent.js";</p> <p>export class BidOffersComponent extends ViewComponent {</p> <pre><code>isPublic = true;

template = `
    &lt;button (click)="processMyData(30, 'John')"&gt;
        Call Parent Function
    &lt;/button&gt;
`;

myMethodSignature(age, name){}
</code></pre> <p>}</p> <p>In addition to using <code>&lt;st-element&gt;</code> component props, there are other means available for component to component communication such as <code>Pub/Sub</code>, both <code>@Proxy</code> and <code>ref</code> which is done to through <code>&lt;st-element&gt;</code> again, and the <code>Service</code> which is a global kind. (see to the Component Communication).</p> <p></p> <p>Embieding component in your regular HTML or within other Frameworks</p> <p>When it comes to components, Still.js provides the Lone Component which only require to reference the CDN for both CSS and JavaScript files thereby not needing to create a Still.js project, therefore, this approach can be followed either for small use case as well as for complex ones such as Microfrontend. (follow do documentation here)</p> <p> </p>

index.htmlCounterComponent.jsroute.map.js <pre><code>&lt;!DOCTYPE html&gt;
&lt;html lang="en"&gt;
    &lt;head&gt;
        &lt;script&gt; STILL_HOME = 'microfronteds/still/' &lt;/script&gt;
        &lt;link href="https://cdn.jsdelivr.net/npm/@stilljs/core@latest/@still/ui/css/still.css" rel="stylesheet"&gt;
        &lt;script src="https://cdn.jsdelivr.net/npm/@stilljs/core@latest/@still/lone.js"type="module"&gt;&lt;/script&gt;
    &lt;/head&gt;
    &lt;body&gt;
        &lt;st-element component="CounterComponent"&gt;&lt;/st-element&gt;
    &lt;/body&gt;
&lt;/html&gt;
</code></pre> <pre><code>/** 
 * This file will be place inside the components folder
 * according to the above folder structure 
 * */
export class CounterComponent extends ViewComponent {

    isPublic = true;
    count = 0;

    template = `
    &lt;div&gt;
        &lt;p&gt;My counter state is @count&lt;/p&gt;
        &lt;button (click)="increment()"&gt;Increment (@count)&lt;/button&gt;
    &lt;/div&gt;
    `;

    increment() {
        this.count = this.count.value + 1;
    }
}
</code></pre> <pre><code>/** 
 * This file will be placed in the same level as app/ folder, 
 * and both are inside the still folder
 * */
export const stillRoutesMap = {
    viewRoutes: {
        regular: {
            CounterComponent: { path: "app/components/" }
        },
        lazyInitial: {}
    }
}
</code></pre> <p>We can add our components in our HTML/App (React, Angular, etc.) by using<code>&lt;st-element&gt;</code> tag instead of depending on the Still.js Application container to render the components, as it (Application container) is totally inexistent in this case.</p> <p>Component creation</p> <p>Although we don't have Still project structure in CDN mode, it's always recommended to use the still-cli to generate components, as this is the way the routes will be automatically added/managed in addition to the component generation.</p> <p>Routing and route.map.js file</p> <p>Despite Still App container is not available in the CND mode, navigation feature is still available, plus, it's needed for the framework to know how to locate the components, hence the route.map.js file.</p> <p></p>

index.html <pre><code>&lt;!DOCTYPE html&gt;
&lt;html lang="en"&gt;

&lt;head&gt;
    &lt;meta charset="UTF-8"&gt;
    &lt;meta http-equiv="X-UA-Compatible" content="IE=Edge"&gt;
    &lt;meta content="width=device-width, initial-scale=1" name="viewport" /&gt;
    &lt;title&gt;StillJS&lt;/title&gt;
    &lt;!-- Bellow (STILL_HOME) is the Still env variable to inform where to look for components --&gt;
    &lt;script&gt; STILL_HOME = 'micro/still/' &lt;/script&gt;
    &lt;!-- Since the Still.js files are present locally we point to it instead of the CDN --&gt;
    &lt;link href="micro/still/@still/ui/css/still.css" rel="stylesheet"&gt;
    &lt;script src="micro/still/@still/lone.js" type="module"&gt;&lt;/script&gt;
&lt;/head&gt;

&lt;body&gt;

    &lt;div&gt;
        This is a regular HTML page, let's test the Lone component
        feature in Still.js and
        &lt;!-- Bellow component (DummyComponent) need to be created as in the point (1.2) --&gt;
        &lt;st-element component="DummyComponent"&gt;&lt;/st-element&gt;
    &lt;/div&gt;

&lt;/body&gt;
</code></pre> <p>Component creation consideration</p> <p>Unlike the CDN scenario, we don't have to use the <code>--lone</code> option when creating Lone component having the whole Still.js folder structure and files.</p> <p>Once the Still.js setup is done for our application, we then need to run it, in this case the process will be the same as point 1.5.</p> <p></p> <p>Microfrontend considerations</p> <p>Although Lone Components don't run within the Still.js Application container, they still support all core framework features — like reactivity, services, routing, authorization, etc. — making them suitable for a Microfrontend architecture.</p>
